+    return null;
+  }
+  if (!Number.isFinite(reloaded.expires) || Date.now() >= reloaded.expires) {
+    return null;
+  }
+  if (
+    params.requireChange &&
+    params.previous &&
+    !hasOAuthCredentialChanged(params.previous, reloaded)
+  ) {
